INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (1948, 203925, 2, 2175, '傻瓜日记(3)', '总是在想：如果有一天，我可以用潇洒而又从容的步伐走过秋的视线，那我就不再惧怕只有我一个人的明天。
<br>爱情不是唯一，却是必需。也许那种彼此间相互关怀，彼此间相互在意的那种感觉已成过去。然而，总是相信在以后的日子里忽然想起，彼此心里不再有涟漪，却仍有感激。是不是最后，是不是唯一，会不会在一起，在彼此眼里忽然变得不再重要，而且既觉得好笑又滑稽。没有过憧憬的爱情，不叫爱情。但是，有了太多幻想和梦想的爱情，往往又不切合实际。最终，走向分离……
<br>我和秋的爱情，有太多梦想，没来得及实现，就走向了分离。我知道我爱他，胜过爱我自己。所以即便是散了，我还是会一个人去完成我和他的梦想。是的，我会！
<br>不知道为什么自己明明是一个那么感性的人，却总是要假装坚强，总是要理智得让人心疼。明明是那么的多愁善感，却总是假装勇敢乐观。明明需要有个人来安慰，来陪伴。明明需要有颗心来读懂，来谅解。可是，却又固执的紧抿着唇，倔强的不再需要爱情。
<br>拒绝爱情的女生，是我啊！其实我好喜欢自己的这个网名。以前的樱子是因为他而存在的，现在的这个女生却是因为自己而存在的。意义不同，心境不同。守着他的回忆过一辈子，其实我并不觉得这有什么难，我愿意，也乐意，真的！之前做的争取，之前做的一切，我后悔了。因为没有必要挽回，默默地去面对，默默地去接受，其实挺好的。                                璇  03年5月27日', '总是在想：如果有一天，我可以用潇洒而又从容的步伐走过秋的视线，那我就不再惧怕只有我一个人的明天。

爱情不是唯一，却是必需。也许那种彼此间相互关怀，彼此间相互在意的那种感觉已成过去。然而，总是相信在以后的日子里忽然想起，彼此心里不再有涟漪，却仍有感激。是不是最后，是不是唯一，会不会在一起，在彼此眼里忽然变得不再重要，而且既觉得好笑又滑稽。没有过憧憬的爱情，不叫爱情。但是，有了太多幻想和梦想的爱情，往往又不切合实际。最终，走向分离……

我和秋的爱情，有太多梦想，没来得及实现，就走向了分离。我知道我爱他，胜过爱我自己。所以即便是散了，我还是会一个人去完成我和他的梦想。是的，我会！

不知道为什么自己明明是一个那么感性的人，却总是要假装坚强，总是要理智得让人心疼。明明是那么的多愁善感，却总是假装勇敢乐观。明明需要有个人来安慰，来陪伴。明明需要有颗心来读懂，来谅解。可是，却又固执的紧抿着唇，倔强的不再需要爱情。

拒绝爱情的女生，是我啊！其实我好喜欢自己的这个网名。以前的樱子是因为他而存在的，现在的这个女生却是因为自己而存在的。意义不同，心境不同。守着他的回忆过一辈子，其实我并不觉得这有什么难，我愿意，也乐意，真的！之前做的争取，之前做的一切，我后悔了。因为没有必要挽回，默默地去面对，默默地去接受，其实挺好的。                                璇  03年5月27日', NULL, '2003-06-02 12:37:00', 2, '20030724225707_bbsid_203925_board_2_84001228f0.html', '20030724225707');
